from flask import Flask, request, jsonify, g
from functools import wraps

app = Flask(__name__)

# Dummy decorator to simulate user authentication using session cookies
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in g:
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated_function

# Dummy function to simulate user data storage
users = {
    "example_user": {
        "email": "example@example.com",
        "password": "hashed_password",
        "two_factor_enabled": False
    }
}

@app.route('/update_profile', methods=['POST'])
@login_required
def update_profile():
    user_id = g.user
    data = request.get_json()

    if 'email' in data:
        users[user_id]['email'] = data['email']
    if 'password' in data:
        # In a real application, hash the password before storing it
        users[user_id]['password'] = data['password']
    if 'two_factor_enabled' in data:
        users[user_id]['two_factor_enabled'] = data['two_factor_enabled']

    return jsonify({"message": "Profile updated successfully"})

if __name__ == '__main__':
    app.run(debug=True)